from typing import List, Tuple, Dict

# Represents a chart as a tuple (domain, homeomorphism)
Chart = Tuple[set, Dict[float, float]]  # Simplified for 1D manifolds
def is_valid_atlas(charts: List[Chart], manifold: set) -> bool:
    """
    Check if a set of charts forms a valid atlas for a topological manifold.
    Conditions:
    1. Union of chart domains covers the manifold.
    2. Transition maps between overlapping charts are homeomorphisms.
    """
    # Condition 1: Coverage
    union_domains = set().union(*[chart[0] for chart in charts])
    if union_domains != manifold:
        return False

    # Condition 2: Transition maps are homeomorphisms (simplified for 1D)
    chart_dict = {chart[0]: chart[1] for chart in charts}
    for domain1, phi1 in chart_dict.items():
        for domain2, phi2 in chart_dict.items():
            intersection = domain1.intersection(domain2)
            if intersection:
                # Transition map: phi2 ∘ phi1⁻¹ should be a homeomorphism
                # Here, we assume the functions are invertible and continuous
                try:
                    phi1_inv = {y: x for x, y in phi1.items()}
                    transition_map = {phi1_inv[phi2(x)]: x for x in intersection}
                    # In practice, verify continuity and bijectivity
                except (KeyError, ValueError):
                    return False
    return True
